mapper.select:
SELECT 
  FROM  TB_HPCM_INFO A
 WHERE  A.HPCM_ID = #{hpcmId}

mapper.insert:
INSERT  INTO TB_HPCM_INFO
      ( HPCM_ID
      , HPCM_SE_CODE
      , HPCM_DFN
      , HPCM_DC
      , FRST_REGIST_PNTTM
      , FRST_REGISTER_ID )
VALUES  ( #{hpcmId}
        , #{hpcmSeCode}
        , #{hpcmDf}
